export default async function(Module, entityId, C, API) {
  const e = window.App.entities[window.App.C.GetEntityName(entityId)];
  const speakerName = e.name;
  
  // VÒNG LẶP SỐNG CÒN: Chạy đến khi nào đủ 10 câu mới thoát!
  while (e.npcProgress.solved < e.npcProgress.total) {
    let currentScore = e.npcProgress.solved;
    // 1. Sinh số ngẫu nhiên
    const n1 = Math.floor(Math.random() * 60) + 1;
    const n2 = Math.floor(Math.random() * 60) + 1;
    const correct = n1 + n2;
    const wrong = correct + (Math.random() > 0.5 ? 2 : -1);

    // 2. Xáo trộn đáp án
    const choices = [
      { text: `Là **${correct}** ạ`, isCorrect: true },
      { text: `Là ${wrong} ạ` , isCorrect: false }
    ];
    if (Math.random() > 0.5) choices.reverse();

    // 3. Chuẩn bị nội dung
    const questionText = `### 🍎 Thử thách bé yêu (${currentScore}/${e.npcProgress.total})\n\n**${n1} + ${n2} = ?**`;
    const choiceTexts = choices.map(c => c.text);

    const selectedIdx = await API.Ask(entityId, speakerName, questionText, choiceTexts);

    if (selectedIdx === -1) {
      console.log("🏃 Học sinh đã bỏ chạy khỏi lớp Toán!");
      return false; // Thoát khỏi Mini-game ngay lập tức và trả về false (Thua cuộc)
    }

    const isRight = choices[selectedIdx].isCorrect;

    // 5. Kiểm tra đáp án
    if (isRight) {
      window.TriggerFeedback(true);
      window.UpdateQuestProgress(entityId,true); 
    } else {
      window.TriggerFeedback(false);
      await API.Say(entityId, speakerName, "### ❌ Sai mất rồi!\n\nĐừng buồn, thử tính lại cẩn thận hơn ở câu này nhé!");
    }
  }

  // Khen thưởng chung cuộc
  await API.Say(entityId, speakerName, `### 🎉 Tuyệt vời!\n\nEm đã xuất sắc giải được ${e.npcProgress.total} câu liên tiếp. Mời em đi tiếp!`);

  return true; // Báo hiệu cho hàm gọi nó biết là đã chiến thắng
}
